  // --- Estados del Juego ---
  const [fase, setFase] = useState<FaseJuego>(FaseJuego.INICIO);
  const [numJugadores, setNumJugadores] = useState<number>(3);
  const [nombresJugadores, setNombresJugadores] = useState<string[]>([]);
  const [palabraSecreta, setPalabraSecreta] = useState<string>('');

  // Estado para impostores
  const [impostoresIndices, setImpostoresIndices] = useState<number[]>([]);
  const [impostoresEncontrados, setImpostoresEncontrados] = useState<number[]>([]); // Nuevo: Rastrear encontrados

  const [jugadorActual, setJugadorActual] = useState<number>(0);
  const [jugadorVotadoIndex, setJugadorVotadoIndex] = useState<number | null>(null);
  const [intentosRestantes, setIntentosRestantes] = useState<number>(1);
  const [historialVotos, setHistorialVotos] = useState<number[]>([]);

  // Estado para persistencia de configuración
  const [configGuardada, setConfigGuardada] = useState<{
    numJugadores: number;
    numImpostores: number;
    nombres: string[];
  } | undefined>(undefined);

  // --- Lógica del Juego ---

  const handleIniciarPartida = (nJugadores: number, nImpostores: number, palabra: string, nombres: string[]) => {
    const nombresParaJuego = nombres.length > 0 
        ? nombres.map((n, i) => n.trim() ? n.trim() : `Jugador ${i + 1}`) 
        : Array.from({length: nJugadores}, (_, i) => `Jugador ${i + 1}`);

    setConfigGuardada({
        numJugadores: nJugadores,
        numImpostores: nImpostores,
        nombres: nombres
    });

    setNumJugadores(nJugadores);
    setPalabraSecreta(palabra);
    setNombresJugadores(nombresParaJuego);
    setHistorialVotos([]);
    setImpostoresEncontrados([]); // Resetear encontrados

    // Configurar intentos: 
    if (nJugadores === 3 && nImpostores === 1) {
      setIntentosRestantes(1);
    } else {
      // Intentos = Número de impostores + 1 margen de error (opcional) o exacto. 
      // El usuario pidió "hasta que se encuentren los tres o se acaben los intentos".
      // Vamos a dar 1 intento fallido extra si hay muchos jugadores, o estricto.
      // Lógica actual: Intentos = Num Impostores + 1 (para dar un margen de error)
      setIntentosRestantes(nImpostores + 1);
    }

    const indicesDisponibles = Array.from({ length: nJugadores }, (_, i) => i);
    const nuevosImpostores: number[] = [];

    for (let i = 0; i < nImpostores; i++) {
      const randomIndex = Math.floor(Math.random() * indicesDisponibles.length);
      nuevosImpostores.push(indicesDisponibles[randomIndex]);
      indicesDisponibles.splice(randomIndex, 1);
    }

    setImpostoresIndices(nuevosImpostores);
    setJugadorActual(0);
    setFase(FaseJuego.ESPERANDO_JUGADOR);
  };

  const handleVerRol = () => {
    soundManager.playReveal();
    setFase(FaseJuego.VIENDO_ROL);
  };

  const handleSiguiente = () => {
    soundManager.playClick();
    const siguienteIndex = jugadorActual + 1;

    if (siguienteIndex < numJugadores) {
      setJugadorActual(siguienteIndex);
      setFase(FaseJuego.ESPERANDO_JUGADOR);
    } else {
      soundManager.playStart();
      setFase(FaseJuego.FINAL);
    }
  };

  const handleIrAVotacion = () => {
    soundManager.playClick();
    setFase(FaseJuego.VOTACION);
  };

  const handleVotar = (indiceVotado: number) => {
    setJugadorVotadoIndex(indiceVotado);
    setHistorialVotos(prev => [...prev, indiceVotado]);
    setFase(FaseJuego.RESULTADO);

    const esImpostor = impostoresIndices.includes(indiceVotado);

    if (esImpostor) {
      soundManager.playWin();
      // Agregar a lista de encontrados si no estaba ya
      // IMPORTANTE: Al actualizar el estado aquí, el componente se re-renderizará con el nuevo estado.
      if (!impostoresEncontrados.includes(indiceVotado)) {
        setImpostoresEncontrados(prev => [...prev, indiceVotado]);
      }
    } else {
      soundManager.playLoss();
      setIntentosRestantes(prev => prev - 1);
    }
  };

  const handleSeguirVotando = () => {
    setJugadorVotadoIndex(null);
    setFase(FaseJuego.VOTACION);
  };

  const handleNuevaPartida = () => {
    soundManager.playClick();
    setFase(FaseJuego.INICIO);
    setPalabraSecreta('');
    setImpostoresIndices([]);
    setImpostoresEncontrados([]);
    setJugadorActual(0);
    setJugadorVotadoIndex(null);
    setHistorialVotos([]);
  };

  // --- Renderizado ---

  return (
    <div className={`min-h-screen flex flex-col p-4 transition-colors duration-300 overflow-x-hidden`}>

      {/* Fondo decorativo */}
      {!settings.sinAnimaciones && (
        <>
           <div className="fixed top-10 left-10 w-32 h-32 bg-blue-500/10 dark:bg-brand-primary/10 rounded-full blur-3xl pointer-events-none z-0"></div>
           <div className="fixed bottom-10 right-10 w-40 h-40 bg-violet-500/10 dark:bg-brand-accent/10 rounded-full blur-3xl pointer-events-none z-0"></div>
        </>
      )}

      {/* Contenedor Principal */}
      <main className="flex-grow flex flex-col items-center justify-center w-full max-w-md mx-auto relative z-10 my-4">

        {fase === FaseJuego.INICIO && (
          <PantallaInicio 
            onIniciarPartida={handleIniciarPartida} 
            onOpenSettings={() => setShowSettings(true)}
            initialConfig={configGuardada}
          />
        )}

        {fase === FaseJuego.ESPERANDO_JUGADOR && (
          <PantallaEsperando 
            nombreJugador={nombresJugadores[jugadorActual]} 
            onVerRol={handleVerRol} 
          />
        )}

        {fase === FaseJuego.VIENDO_ROL && (
          <PantallaRol
            esImpostor={impostoresIndices.includes(jugadorActual)}
            palabraSecreta={palabraSecreta}
            onSiguiente={handleSiguiente}
          />
        )}

        {fase === FaseJuego.FINAL && (
          <PantallaFinal 
            onIrAVotacion={handleIrAVotacion}
            onNuevaPartida={handleNuevaPartida} 
          />
        )}

        {fase === FaseJuego.VOTACION && (
          <PantallaVotacion
            nombresJugadores={nombresJugadores}
            onVotar={handleVotar}
            jugadoresVotados={historialVotos}
          />
        )}

        {fase === FaseJuego.RESULTADO && jugadorVotadoIndex !== null && (
          <PantallaResultado
            nombreVotado={nombresJugadores[jugadorVotadoIndex]}
            esImpostorCorrecto={impostoresIndices.includes(jugadorVotadoIndex)}
            nombresImpostores={impostoresIndices.map(i => nombresJugadores[i])}
            palabraSecreta={palabraSecreta}
            onNuevaPartida={handleNuevaPartida}
            intentosRestantes={intentosRestantes}
            onSeguirVotando={handleSeguirVotando}
            // Aquí usamos impostoresEncontrados.length porque el estado ya incluye al actual si fue acierto
            impostoresEncontradosCount={impostoresEncontrados.length}
            totalImpostores={impostoresIndices.length}
          />
        )}

      </main>

      {showSettings && (
        <MenuAccesibilidad 
          settings={settings} 
          setSettings={setSettings} 
          onClose={() => setShowSettings(false)} 
        />
      )}

      {/* Footer */}
      <footer className="w-full py-4 text-center z-10 mt-auto opacity-70">
        <p className="text-slate-500 dark:text-slate-500 text-xs font-semibold">
          © {new Date().getFullYear()} El Impostor
        </p>
      </footer>
    </div>
  );
}

export default App;

import React from 'react';
import { CheckCircle2, XCircle, RotateCcw, UserX, ArrowLeft, Search } from 'lucide-react';

interface PantallaResultadoProps {
  nombreVotado: string;
  esImpostorCorrecto: boolean;
  nombresImpostores: string[];
  palabraSecreta: string;
  onNuevaPartida: () => void;
  intentosRestantes: number;
  onSeguirVotando: () => void;
  impostoresEncontradosCount: number;
  totalImpostores: number;
}

const PantallaResultado: React.FC<PantallaResultadoProps> = ({ 
  nombreVotado, 
  esImpostorCorrecto, 
  nombresImpostores, 
  palabraSecreta,
  onNuevaPartida,
  intentosRestantes,
  onSeguirVotando,
  impostoresEncontradosCount,
  totalImpostores
}) => {

  // Lógica de finalización:
  const todosEncontrados = impostoresEncontradosCount >= totalImpostores;
  const sinIntentos = intentosRestantes <= 0;

  const juegoTerminado = todosEncontrados || sinIntentos;
  const esVictoriaFinal = todosEncontrados;
  const faltantes = totalImpostores - impostoresEncontradosCount;

  return (
    <div className="flex flex-col items-center justify-center w-full max-w-sm px-6 text-center space-y-8 animate-[fadeIn_0.5s_ease-out] py-6">

      {/* Icono de Resultado */}
      <div className="relative">
        <div className={`absolute inset-0 blur-3xl rounded-full opacity-30 ${esImpostorCorrecto ? 'bg-green-600' : 'bg-red-600'}`}></div>
        {esImpostorCorrecto ? (
          <CheckCircle2 className="w-32 h-32 text-green-600 relative z-10 drop-shadow-xl" />
        ) : (
          <XCircle className="w-32 h-32 text-red-600 relative z-10 drop-shadow-xl" />
        )}
      </div>

      {/* Título y Mensajes */}
      <div className="space-y-3">
        <h1 className={`text-4xl font-black uppercase ${esImpostorCorrecto ? 'text-green-700 dark:text-green-500' : 'text-red-700 dark:text-red-500'}`}>
          {esImpostorCorrecto 
            ? (esVictoriaFinal ? '¡VICTORIA TOTAL!' : '¡ATRAPADO!') 
            : (juegoTerminado ? '¡DERROTA!' : '¡FALLASTE!')}
        </h1>

        <p className="text-slate-900 dark:text-white text-xl font-bold leading-relaxed">
          {esImpostorCorrecto 
            ? (esVictoriaFinal 
                ? `¡Genial! Has encontrado a todos. ${nombreVotado} era el último impostor.`
                : `¡Bien hecho! ${nombreVotado} es un impostor. Pero cuidado, aún quedan más.`)
            : `¡Oh no! ${nombreVotado} NO era impostor.`}
        </p>

        {/* Estado del juego (Impostores restantes / Intentos) */}
        {!juegoTerminado && (
           <div className="flex flex-col gap-2 pt-2 items-center">
              {esImpostorCorrecto && (
                <div className="bg-blue-100 dark:bg-blue-900/30 text-blue-800 dark:text-blue-300 px-4 py-2 rounded-lg text-sm font-bold border border-blue-200 dark:border-blue-800 flex items-center gap-2">
                   <Search className="w-4 h-4" />
                   Faltan {faltantes} {faltantes === 1 ? 'impostor' : 'impostores'}
                </div>
              )}

              {!esImpostorCorrecto && (
                 <div className="bg-yellow-100 dark:bg-yellow-900/30 text-yellow-800 dark:text-yellow-400 px-4 py-2 rounded-lg text-sm font-bold border border-yellow-300 dark:border-yellow-700">
                    Te quedan {intentosRestantes} {intentosRestantes === 1 ? 'intento' : 'intentos'}
                 </div>
              )}
           </div>
        )}
      </div>

      {/* Revelación Final (Solo si acaba el juego) */}
      {juegoTerminado && (
        <div className="w-full bg-white dark:bg-slate-800/80 p-6 rounded-2xl border-2 border-slate-300 dark:border-slate-700 space-y-4 shadow-xl">

          <div className="space-y-1">
            <span className="text-xs uppercase tracking-wider text-slate-600 dark:text-slate-500 font-black">Palabra Secreta</span>
            <div className="text-2xl font-black text-slate-900 dark:text-white bg-slate-100 dark:bg-slate-700 py-2 rounded-lg border border-slate-200 dark:border-transparent">
              {palabraSecreta}
            </div>
          </div>

          <div className="space-y-3 pt-3 border-t-2 border-slate-200 dark:border-slate-700">
            <span className="text-xs uppercase tracking-wider text-red-700 dark:text-brand-danger font-black flex items-center justify-center gap-1">
              <UserX className="w-4 h-4" />
              Todos los Impostores
            </span>
            <div className="flex flex-wrap gap-2 justify-center">
              {nombresImpostores.map((imp, idx) => (
                <span key={idx} className="bg-red-100 dark:bg-brand-danger/20 text-red-800 dark:text-brand-danger border border-red-200 dark:border-brand-danger/30 px-3 py-1 rounded-full font-bold">
                  {imp}
                </span>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Botones */}
      <div className="w-full space-y-3">
        {!juegoTerminado ? (
          <button
            onClick={onSeguirVotando}
            className="w-full py-4 bg-blue-700 hover:bg-blue-800 dark:bg-brand-primary dark:hover:bg-blue-600 text-white font-bold text-lg rounded-xl shadow-xl transform transition-all active:scale-95 flex items-center justify-center gap-2"
          >
            <ArrowLeft className="w-6 h-6" />
            SEGUIR BUSCANDO
          </button>
        ) : (
          <button
            onClick={onNuevaPartida}
            className={`w-full py-4 font-bold text-lg rounded-xl shadow-xl transform transition-all active:scale-95 flex items-center justify-center gap-2 ${
               esVictoriaFinal 
               ? 'bg-green-600 hover:bg-green-700 text-white' 
               : 'bg-slate-800 hover:bg-slate-900 dark:bg-slate-100 dark:hover:bg-white text-white dark:text-slate-900'
            }`}
          >
            <RotateCcw className="w-6 h-6" />
            JUGAR OTRA VEZ
          </button>
        )}
      </div>
    </div>
  );
};

