import React, { useState } from 'react';
import { CheckCircle2, UserX, UserCheck, ShieldQuestion, ArrowLeft, BookOpenText } from 'lucide-react';
import { soundManager } from '../utils/audio';

interface PantallaRolProps {
  nombreJugador: string;
  esImpostor: boolean;
  palabraSecreta: string;
  onSiguiente: () => void;
}

const PantallaRol: React.FC<PantallaRolProps> = ({ nombreJugador, esImpostor, palabraSecreta, onSiguiente }) => {
  const [abierto, setAbierto] = useState(false);
  const [haSidoRevelada, setHaSidoRevelada] = useState(false);

  const manejarAbrirCerrar = () => {
    soundManager.playReveal(); // Usamos el sonido de revelación para el libro
    setAbierto(!abierto);
    if (!haSidoRevelada) setHaSidoRevelada(true);
  };

  return (
    <div className="flex flex-col items-center justify-center w-full max-w-sm px-6 text-center space-y-8 animate-fade-in py-4">

