          Expediente Secreto
        </h2>
        <p className="text-xs text-slate-400 dark:text-slate-500 font-bold">
          {abierto ? 'Toca para cerrar el libro' : 'Abre el libro para ver tu rol'}
        </p>
      </div>

      {/* Contenedor del Libro 3D */}
      <div 
        className="relative w-full h-[420px] perspective-2000 cursor-pointer group"
        onClick={manejarAbrirCerrar}
      >
        {/* Cuerpo del Libro (Páginas interiores) */}
        <div className="absolute inset-0 bg-slate-50 dark:bg-slate-900 rounded-r-2xl border-y-2 border-r-2 border-slate-300 dark:border-slate-700 shadow-2xl flex flex-col items-center justify-center p-8 overflow-hidden">
          {/* Efecto de páginas apiladas en el borde derecho */}
          <div className="absolute right-0 top-0 bottom-0 w-2 bg-gradient-to-l from-slate-300/30 to-transparent"></div>

          <div className="relative z-10 space-y-6 w-full">
            {esImpostor ? (
              <div className="animate-[fadeIn_0.5s_ease-out]">
                <div className="w-20 h-20 bg-red-100 dark:bg-brand-danger/20 rounded-full flex items-center justify-center mx-auto mb-4 border-2 border-red-200 dark:border-brand-danger/30">
                  <UserX className="w-12 h-12 text-red-600 dark:text-brand-danger" />
                </div>
                <h4 className="text-red-700 dark:text-brand-danger font-black text-4xl uppercase tracking-tighter italic mb-2">¡IMPOSTOR!</h4>
                <div className="p-4 bg-red-600/5 dark:bg-brand-danger/10 rounded-xl border-l-4 border-red-600">
                  <p className="text-sm font-bold text-slate-700 dark:text-slate-300">
                    No conoces la palabra. Tu misión es infiltrarte y adivinarla.
                  </p>
                </div>
              </div>
